	 ARMword       instr,
	 ARMword       value)
{
  switch (BITS (5, 7))
    {
    case 0: /* cfmv32al */
      cirrus_not_implemented ("cfmv32al");
      break;

    case 1: /* cfmv32am */
      cirrus_not_implemented ("cfmv32am");
